import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat resultFormat = baseFormat.withFirstRecordAsHeader();

        // It should be a new instance, not the same as base
        assertNotSame(baseFormat, resultFormat);

        // The header should be set (non-null)
        assertNotNull(resultFormat.getHeader());

        // The skipHeaderRecord flag should be true
        assertTrue(resultFormat.getSkipHeaderRecord());

        // The header from withHeader() should be empty array (default)
        assertEquals(0, resultFormat.getHeader().length);

        // Other properties should remain same as baseFormat, e.g. delimiter
        assertEquals(baseFormat.getDelimiter(), resultFormat.getDelimiter());
    }
}
